import pymongo
from bson.code import Code
import json

def connect_to_mongodb(host='localhost', port=27017, db_name='mydatabase'):
    """Establishes a connection to MongoDB and returns the database object."""
    try:
        client = pymongo.MongoClient(host, port)
        db = client[db_name]
        print(f"Connected to MongoDB: {host}:{port}/{db_name}")
        return db
    except pymongo.errors.ConnectionFailure as e:
        print(f"Could not connect to MongoDB: {e}")
        return None

def insert_sample_data(db, collection_name='mycollection'):
    """Inserts some sample data into the specified collection if it's empty."""
    collection = db[collection_name]
    if collection.count_documents({}) == 0:
        sample_data = [
            {'name': 'Alice', 'age': 30, 'city': 'New York', 'tags': ['tech', 'marketing']},
            {'name': 'Bob', 'age': 24, 'city': 'Los Angeles', 'tags': ['design']},
            {'name': 'Charlie', 'age': 35, 'city': 'New York', 'tags': ['finance', 'tech']},
            {'name': 'David', 'age': 29, 'city': 'Chicago', 'tags': ['sales']},
            {'name': 'Eve', 'age': 40, 'city': 'Los Angeles', 'tags': ['hr', 'management']},
            {'name': 'Frank', 'age': 22, 'city': 'Miami', 'tags': ['tech']},
            {'name': 'Grace', 'age': 31, 'city': 'New York', 'tags': ['finance']},
        ]
        collection.insert_many(sample_data)
        print(f"Inserted {len(sample_data)} sample documents into '{collection_name}'.")
    else:
        print(f"Collection '{collection_name}' already contains data. Skipping sample data insertion.")

def advanced_javascript_filter_query(db, collection_name='mycollection', js_filter_expression=""):
    """
    Executes a MongoDB query using the $where operator with a user-provided
    JavaScript expression for filtering.
    """
    collection = db[collection_name]

    if not js_filter_expression:
        print("Error: No JavaScript filter expression provided.")
        return []

    try:
        # Using bson.code.Code for the JavaScript expression
        # The $where operator executes the JavaScript code directly on the server.
        # 'this' refers to the current document in the JavaScript context.
        query = {"$where": Code(js_filter_expression)}

        print(f"\nExecuting query with $where: '{js_filter_expression}'")
        results = list(collection.find(query))
        return results
    except pymongo.errors.OperationFailure as e:
        print(f"MongoDB Operation Failure: {e}")
        print("Please ensure your JavaScript expression is valid and does not cause server-side errors.")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []

def main():
    db = connect_to_mongodb()
    if db is None:
        return

    collection_name = 'advanced_users'
    insert_sample_data(db, collection_name)

    print("\n--- Advanced Data Filtering Service ---")
    print("This service allows you to filter MongoDB documents using server-side JavaScript via the $where operator.")
    print("In your JavaScript expression, 'this' refers to the current document.")
    print("Example expressions:")
    print("  - this.age > 30 && this.city == 'New York'")
    print("  - this.name.startsWith('A') || this.age < 25")
    print("  - this.tags && this.tags.includes('tech')")
    print("  - this.age % 2 == 0")

    while True:
        js_expression = input("\nEnter JavaScript filter expression (or 'exit' to quit): ").strip()
        if js_expression.lower() == 'exit':
            break

        if not js_expression:
            print("Expression cannot be empty. Please try again.")
            continue

        filtered_documents = advanced_javascript_filter_query(db, collection_name, js_expression)

        if filtered_documents:
            print(f"\nFound {len(filtered_documents)} document(s):")
            for doc in filtered_documents:
                print(json.dumps(doc, indent=2))
        else:
            print("No documents found matching the criteria or an error occurred.")

    print("\nExiting Advanced Data Filtering Service.")

if __name__ == "__main__":
    main()